// ===== src/Components/Admin/AdminSidebar.jsx =====
import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAdminAuth } from '../../Context/AdminAuthContext';
import { ROUTES } from '../../Config/Routes';
import '../../Styles/Admin.css';

/**
 * AdminSidebar Component - GOD MODE
 * Collapsible sidebar with navigation and user info
 * 
 * @param {Object} props
 * @param {boolean} props.collapsed - Sidebar collapsed state
 * @param {Function} props.onToggle - Toggle handler
 * @param {boolean} props.mobile - Mobile mode
 * @param {Function} props.onClose - Close handler for mobile
 */
const AdminSidebar = ({ 
  collapsed = false, 
  onToggle,
  mobile = false,
  onClose 
}) => {
  const [activeItem, setActiveItem] = useState(null);
  const { admin, logout } = useAdminAuth();
  const location = useLocation();

  useEffect(() => {
    // Find active menu item based on current path
    const findActiveItem = () => {
      for (const section of navigation) {
        const item = section.items.find(item => 
          location.pathname === item.path || 
          (item.path !== ROUTES.ADMIN_DASHBOARD && location.pathname.startsWith(item.path))
        );
        if (item) return item.id;
      }
      return null;
    };

    setActiveItem(findActiveItem());
  }, [location]);

  const navigation = [
    {
      id: 'dashboard',
      section: 'Main',
      items: [
        { 
          id: 'dashboard', 
          path: ROUTES.ADMIN_DASHBOARD, 
          label: 'Dashboard', 
          icon: '📊',
          description: 'Overview and analytics'
        },
        { 
          id: 'bookings', 
          path: ROUTES.ADMIN_BOOKINGS, 
          label: 'Bookings', 
          icon: '📅',
          description: 'Manage all bookings',
          badge: '12'
        },
        { 
          id: 'payments', 
          path: ROUTES.ADMIN_PAYMENTS, 
          label: 'Payments', 
          icon: '💰',
          description: 'Transaction management',
          badge: '3'
        }
      ]
    },
    {
      id: 'management',
      section: 'Management',
      items: [
        { 
          id: 'vehicles', 
          path: ROUTES.ADMIN_VEHICLES, 
          label: 'Vehicles', 
          icon: '🚗',
          description: 'Vehicle inventory'
        },
        { 
          id: 'users', 
          path: '/admin/users', 
          label: 'Users', 
          icon: '👥',
          description: 'User management'
        },
        { 
          id: 'services', 
          path: '/admin/services', 
          label: 'Services', 
          icon: '🔧',
          description: 'Service catalog'
        },
        { 
          id: 'locations', 
          path: '/admin/locations', 
          label: 'Locations', 
          icon: '📍',
          description: 'Branch locations'
        }
      ]
    },
    {
      id: 'reports',
      section: 'Reports',
      items: [
        { 
          id: 'analytics', 
          path: ROUTES.ADMIN_REPORTS, 
          label: 'Analytics', 
          icon: '📈',
          description: 'Business intelligence'
        },
        { 
          id: 'audit', 
          path: '/admin/audit-logs', 
          label: 'Audit Logs', 
          icon: '📋',
          description: 'System activity'
        },
        { 
          id: 'exports', 
          path: '/admin/exports', 
          label: 'Exports', 
          icon: '📎',
          description: 'Data export'
        }
      ]
    },
    {
      id: 'settings',
      section: 'Settings',
      items: [
        { 
          id: 'settings', 
          path: '/admin/settings', 
          label: 'System Settings', 
          icon: '⚙️',
          description: 'Configuration'
        },
        { 
          id: 'profile', 
          path: '/admin/profile', 
          label: 'Profile', 
          icon: '👤',
          description: 'Account settings'
        }
      ]
    }
  ];

  const handleItemClick = (itemId) => {
    setActiveItem(itemId);
    if (mobile && onClose) {
      onClose();
    }
  };

  const handleLogout = async () => {
    await logout();
  };

  return (
    <aside className={`admin-sidebar ${collapsed ? 'collapsed' : ''} ${mobile ? 'mobile' : ''}`}>
      {/* Header */}
      <div className="sidebar-header">
        <Link to={ROUTES.ADMIN_DASHBOARD} className="sidebar-logo" onClick={() => mobile && onClose && onClose()}>
          <span className="logo-text">CAR<span className="gold-text">EASE</span></span>
          {!collapsed && <span className="logo-badge">Admin</span>}
        </Link>

        {!mobile && (
          <button 
            className="sidebar-toggle"
            onClick={onToggle}
            aria-label={collapsed ? 'Expand sidebar' : 'Collapse sidebar'}
          >
            <span className="toggle-icon">{collapsed ? '→' : '←'}</span>
          </button>
        )}
      </div>

      {/* User Info */}
      {admin && (
        <div className="sidebar-user">
          <div className="user-avatar">
            {admin.avatar ? (
              <img src={admin.avatar} alt={admin.name} />
            ) : (
              <span className="avatar-placeholder">
                {admin.name?.charAt(0).toUpperCase()}
              </span>
            )}
          </div>
          {!collapsed && (
            <div className="user-info">
              <span className="user-name">{admin.name}</span>
              <span className="user-role">
                {admin.role === 'super_admin' ? 'Super Admin' : 'Administrator'}
              </span>
              <span className="user-email">{admin.email}</span>
            </div>
          )}
        </div>
      )}

      {/* Navigation */}
      <nav className="sidebar-nav">
        {navigation.map(section => (
          <div key={section.id} className="nav-section">
            {!collapsed && (
              <h3 className="nav-section-title">{section.section}</h3>
            )}
            <ul className="nav-items">
              {section.items.map(item => (
                <li key={item.id} className="nav-item">
                  <Link
                    to={item.path}
                    className={`nav-link ${activeItem === item.id ? 'active' : ''}`}
                    onClick={() => handleItemClick(item.id)}
                    title={collapsed ? item.label : undefined}
                  >
                    <span className="nav-icon">{item.icon}</span>
                    {!collapsed && (
                      <>
                        <span className="nav-label">{item.label}</span>
                        {item.badge && (
                          <span className="nav-badge">{item.badge}</span>
                        )}
                      </>
                    )}
                    {!collapsed && item.description && (
                      <span className="nav-tooltip">{item.description}</span>
                    )}
                  </Link>
                </li>
              ))}
            </ul>
          </div>
        ))}
      </nav>

      {/* Footer */}
      <div className="sidebar-footer">
        <button className="logout-btn" onClick={handleLogout}>
          <span className="logout-icon">🚪</span>
          {!collapsed && <span className="logout-label">Logout</span>}
        </button>

        {!collapsed && (
          <div className="sidebar-footer-info">
            <span className="version">v1.0.0</span>
            <span className="copyright">© CAR EASE</span>
          </div>
        )}
      </div>

      {/* Mobile Close Button */}
      {mobile && (
        <button className="sidebar-close" onClick={onClose} aria-label="Close sidebar">
          ×
        </button>
      )}
    </aside>
  );
};

export default AdminSidebar;

// ===== src/Components/Admin/AdminTable.jsx =====
import React, { useState, useMemo } from 'react';
import Button from '../Common/Button';
import Input from '../Common/Input';
import LoadingSpinner from '../Common/LoadingSpinner';
import '../../Styles/Admin.css';

/**
 * AdminTable Component - GOD MODE
 * Feature-rich data table with sorting, filtering, pagination
 * 
 * @param {Object} props
 * @param {Array} props.columns - Column definitions
 * @param {Array} props.data - Table data
 * @param {boolean} props.loading - Loading state
 * @param {Function} props.onSort - Sort handler
 * @param {Function} props.onFilter - Filter handler
 * @param {Function} props.onPageChange - Page change handler
 * @param {Object} props.pagination - Pagination state
 * @param {Array} props.actions - Row actions
 * @param {boolean} props.selectable - Enable row selection
 * @param {Function} props.onSelect - Selection handler
 * @param {string} props.className - Additional CSS classes
 */
const AdminTable = ({
  columns = [],
  data = [],
  loading = false,
  onSort,
  onFilter,
  onPageChange,
  pagination = { page: 1, limit: 10, total: 0 },
  actions = [],
  selectable = false,
  onSelect,
  className = '',
  ...props
}) => {
  const [sortConfig, setSortConfig] = useState({ key: null, direction: 'asc' });
  const [filters, setFilters] = useState({});
  const [selectedRows, setSelectedRows] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');

  // Handle sort
  const handleSort = (key) => {
    let direction = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
    if (onSort) onSort(key, direction);
  };

  // Handle filter
  const handleFilter = (key, value) => {
    const newFilters = { ...filters, [key]: value };
    setFilters(newFilters);
    if (onFilter) onFilter(newFilters);
  };

  // Handle select all
  const handleSelectAll = () => {
    if (selectedRows.length === data.length) {
      setSelectedRows([]);
      if (onSelect) onSelect([]);
    } else {
      const allIds = data.map(row => row.id);
      setSelectedRows(allIds);
      if (onSelect) onSelect(allIds);
    }
  };

  // Handle select row
  const handleSelectRow = (id) => {
    let newSelected;
    if (selectedRows.includes(id)) {
      newSelected = selectedRows.filter(rowId => rowId !== id);
    } else {
      newSelected = [...selectedRows, id];
    }
    setSelectedRows(newSelected);
    if (onSelect) onSelect(newSelected);
  };

  // Handle page change
  const handlePageChange = (newPage) => {
    if (onPageChange) onPageChange(newPage);
  };

  // Get sort icon
  const getSortIcon = (key) => {
    if (sortConfig.key !== key) return '↕️';
    return sortConfig.direction === 'asc' ? '↑' : '↓';
  };

  // Calculate pagination
  const totalPages = Math.ceil(pagination.total / pagination.limit);
  const startItem = ((pagination.page - 1) * pagination.limit) + 1;
  const endItem = Math.min(pagination.page * pagination.limit, pagination.total);

  return (
    <div className={`admin-table-container ${className}`} {...props}>
      {/* Table Controls */}
      <div className="table-controls">
        <div className="table-search">
          <Input
            type="search"
            placeholder="Search..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            icon="🔍"
          />
        </div>

        {actions.length > 0 && (
          <div className="table-actions">
            {actions.map((action, index) => (
              <Button
                key={index}
                variant={action.variant || 'secondary'}
                size="sm"
                icon={action.icon}
                onClick={() => action.onClick(selectedRows)}
                disabled={action.requireSelection && selectedRows.length === 0}
              >
                {action.label}
              </Button>
            ))}
          </div>
        )}
      </div>

      {/* Table */}
      <div className="table-wrapper">
        <table className="admin-table">
          <thead>
            <tr>
              {selectable && (
                <th className="checkbox-cell">
                  <input
                    type="checkbox"
                    checked={selectedRows.length === data.length && data.length > 0}
                    onChange={handleSelectAll}
                  />
                </th>
              )}
              {columns.map(column => (
                <th
                  key={column.key}
                  className={column.sortable ? 'sortable' : ''}
                  onClick={() => column.sortable && handleSort(column.key)}
                  style={{ width: column.width }}
                >
                  <div className="th-content">
                    {column.label}
                    {column.sortable && (
                      <span className="sort-icon">{getSortIcon(column.key)}</span>
                    )}
                  </div>
                  {column.filterable && (
                    <div className="filter-input">
                      <input
                        type="text"
                        placeholder={`Filter ${column.label}`}
                        value={filters[column.key] || ''}
                        onChange={(e) => handleFilter(column.key, e.target.value)}
                        onClick={(e) => e.stopPropagation()}
                      />
                    </div>
                  )}
                </th>
              ))}
              {actions.length > 0 && <th className="actions-cell">Actions</th>}
            </tr>
          </thead>

          <tbody>
            {loading ? (
              <tr>
                <td colSpan={columns.length + (selectable ? 1 : 0) + (actions.length > 0 ? 1 : 0)}>
                  <div className="table-loading">
                    <LoadingSpinner size="md" color="gold" text="Loading data..." />
                  </div>
                </td>
              </tr>
            ) : data.length === 0 ? (
              <tr>
                <td colSpan={columns.length + (selectable ? 1 : 0) + (actions.length > 0 ? 1 : 0)}>
                  <div className="table-empty">
                    <span className="empty-icon">📭</span>
                    <p>No data available</p>
                  </div>
                </td>
              </tr>
            ) : (
              data.map((row, rowIndex) => (
                <tr key={row.id || rowIndex} className={selectedRows.includes(row.id) ? 'selected' : ''}>
                  {selectable && (
                    <td className="checkbox-cell">
                      <input
                        type="checkbox"
                        checked={selectedRows.includes(row.id)}
                        onChange={() => handleSelectRow(row.id)}
                      />
                    </td>
                  )}
                  {columns.map(column => (
                    <td key={`${row.id}-${column.key}`}>
                      {column.render ? column.render(row[column.key], row) : row[column.key]}
                    </td>
                  ))}
                  {actions.length > 0 && (
                    <td className="actions-cell">
                      <div className="row-actions">
                        {actions.map((action, index) => (
                          <button
                            key={index}
                            className={`action-btn ${action.variant || 'default'}`}
                            onClick={() => action.onClick(row)}
                            title={action.label}
                          >
                            {action.icon}
                          </button>
                        ))}
                      </div>
                    </td>
                  )}
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {!loading && data.length > 0 && (
        <div className="table-pagination">
          <div className="pagination-info">
            Showing {startItem} to {endItem} of {pagination.total} entries
          </div>

          <div className="pagination-controls">
            <button
              className="pagination-btn"
              onClick={() => handlePageChange(pagination.page - 1)}
              disabled={pagination.page === 1}
            >
              ←
            </button>

            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
              let pageNum;
              if (totalPages <= 5) {
                pageNum = i + 1;
              } else if (pagination.page <= 3) {
                pageNum = i + 1;
              } else if (pagination.page >= totalPages - 2) {
                pageNum = totalPages - 4 + i;
              } else {
                pageNum = pagination.page - 2 + i;
              }

              return (
                <button
                  key={pageNum}
                  className={`pagination-btn ${pagination.page === pageNum ? 'active' : ''}`}
                  onClick={() => handlePageChange(pageNum)}
                >
                  {pageNum}
                </button>
              );
            })}

            <button
              className="pagination-btn"
              onClick={() => handlePageChange(pagination.page + 1)}
              disabled={pagination.page === totalPages}
            >
              →
            </button>
          </div>

          <select
            className="pagination-limit"
            value={pagination.limit}
            onChange={(e) => onPageChange && onPageChange(1, parseInt(e.target.value))}
          >
            {[10, 25, 50, 100].map(limit => (
              <option key={limit} value={limit}>{limit} per page</option>
            ))}
          </select>
        </div>
      )}
    </div>
  );
};

export default AdminTable;

// ===== src/Components/Admin/AnalyticsChart.jsx =====
import React from 'react';
import '../../Styles/Admin.css';

/**
 * AnalyticsChart Component - GOD MODE
 * Multiple chart types for admin analytics (No external dependencies)
 * 
 * @param {Object} props
 * @param {string} props.type - Chart type (line, bar, pie, doughnut, radar)
 * @param {Array} props.data - Chart data
 * @param {Object} props.options - Chart options
 * @param {string} props.title - Chart title
 * @param {boolean} props.loading - Loading state
 * @param {string} props.height - Chart height
 * @param {string} props.className - Additional CSS classes
 */
const AnalyticsChart = ({
  type = 'line',
  data = { labels: [], datasets: [] },
  options = {},
  title,
  loading = false,
  height = '300px',
  className = '',
  ...props
}) => {

  // Helper function to get color based on index
  const getColor = (index) => {
    const colors = [
      '#d4af37', // gold
      '#00ff88', // success green
      '#33b5e5', // info blue
      '#ffbb33', // warning yellow
      '#ff4444', // error red
      '#aa80ff', // purple
      '#ff80ab', // pink
      '#80deea', // cyan
      '#ffb74d', // orange
      '#a1887f'  // brown
    ];
    return colors[index % colors.length];
  };

  // Render line chart
  const renderLineChart = () => {
    const { labels = [], datasets = [] } = data;
    if (!labels.length || !datasets.length) return renderNoData();

    const maxValue = Math.max(...datasets.flatMap(d => d.data)) * 1.1;
    const minValue = Math.min(...datasets.flatMap(d => d.data)) * 0.9;
    const range = maxValue - minValue;

    return (
      <div className="chart-svg-container">
        <svg viewBox={`0 0 ${labels.length * 100} 300`} preserveAspectRatio="xMidYMid meet">
          {/* Grid lines */}
          {[0, 1, 2, 3, 4].map(i => (
            <line
              key={`grid-${i}`}
              x1="50"
              y1={50 + i * 50}
              x2={labels.length * 100 - 50}
              y2={50 + i * 50}
              stroke="rgba(212, 175, 55, 0.1)"
              strokeWidth="1"
              strokeDasharray="5,5"
            />
          ))}

          {/* Data lines and points */}
          {datasets.map((dataset, datasetIndex) => {
            const points = dataset.data.map((value, index) => ({
              x: 50 + index * 100,
              y: 250 - ((value - minValue) / range) * 200
            }));

            // Create path for line
            const linePath = points.map((p, i) => 
              `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`
            ).join(' ');

            return (
              <g key={`dataset-${datasetIndex}`}>
                {/* Line */}
                <path
                  d={linePath}
                  fill="none"
                  stroke={dataset.borderColor || getColor(datasetIndex)}
                  strokeWidth="2"
                />

                {/* Area fill (optional) */}
                {dataset.fill && (
                  <path
                    d={`${linePath} L ${points[points.length-1].x} 250 L 50 250 Z`}
                    fill={dataset.backgroundColor || `${getColor(datasetIndex)}33`}
                    opacity="0.1"
                  />
                )}

                {/* Points */}
                {points.map((point, pointIndex) => (
                  <circle
                    key={`point-${datasetIndex}-${pointIndex}`}
                    cx={point.x}
                    cy={point.y}
                    r="4"
                    fill={dataset.pointBackgroundColor || getColor(datasetIndex)}
                    stroke="#ffffff"
                    strokeWidth="2"
                  />
                ))}
              </g>
            );
          })}

          {/* X-axis labels */}
          {labels.map((label, index) => (
            <text
              key={`xlabel-${index}`}
              x={50 + index * 100}
              y="280"
              textAnchor="middle"
              fill="#94a3b8"
              fontSize="12"
            >
              {label}
            </text>
          ))}

          {/* Y-axis labels */}
          {[0, 1, 2, 3, 4].map(i => {
            const value = minValue + (range * (4 - i) / 4);
            return (
              <text
                key={`ylabel-${i}`}
                x="30"
                y={50 + i * 50 + 5}
                textAnchor="end"
                fill="#94a3b8"
                fontSize="10"
              >
                {value.toFixed(0)}
              </text>
            );
          })}
        </svg>
      </div>
    );
  };

  // Render bar chart
  const renderBarChart = () => {
    const { labels = [], datasets = [] } = data;
    if (!labels.length || !datasets.length) return renderNoData();

    const maxValue = Math.max(...datasets.flatMap(d => d.data)) * 1.1;
    const barWidth = 60;
    const groupSpacing = 20;
    const chartWidth = labels.length * (datasets.length * barWidth + groupSpacing);

    return (
      <div className="chart-svg-container">
        <svg viewBox={`0 0 ${chartWidth + 100} 300`} preserveAspectRatio="xMidYMid meet">
          {/* Grid lines */}
          {[0, 1, 2, 3, 4].map(i => (
            <line
              key={`grid-${i}`}
              x1="50"
              y1={50 + i * 50}
              x2={chartWidth + 50}
              y2={50 + i * 50}
              stroke="rgba(212, 175, 55, 0.1)"
              strokeWidth="1"
              strokeDasharray="5,5"
            />
          ))}

          {/* Bars */}
          {labels.map((label, labelIndex) => {
            const groupX = 50 + labelIndex * (datasets.length * barWidth + groupSpacing);

            return datasets.map((dataset, datasetIndex) => {
              const barHeight = (dataset.data[labelIndex] / maxValue) * 200;
              const barX = groupX + datasetIndex * barWidth;
              const barY = 250 - barHeight;

              return (
                <g key={`bar-${labelIndex}-${datasetIndex}`}>
                  <rect
                    x={barX}
                    y={barY}
                    width={barWidth - 4}
                    height={barHeight}
                    fill={dataset.backgroundColor || getColor(datasetIndex)}
                    rx="4"
                    ry="4"
                  />
                  {dataset.label && (
                    <title>{dataset.label}: {dataset.data[labelIndex]}</title>
                  )}
                </g>
              );
            });
          })}

          {/* X-axis labels */}
          {labels.map((label, index) => {
            const groupX = 50 + index * (datasets.length * barWidth + groupSpacing) + (datasets.length * barWidth) / 2;
            return (
              <text
                key={`xlabel-${index}`}
                x={groupX}
                y="280"
                textAnchor="middle"
                fill="#94a3b8"
                fontSize="12"
              >
                {label}
              </text>
            );
          })}

          {/* Y-axis labels */}
          {[0, 1, 2, 3, 4].map(i => {
            const value = (maxValue * i) / 4;
            return (
              <text
                key={`ylabel-${i}`}
                x="30"
                y={250 - i * 50 + 5}
                textAnchor="end"
                fill="#94a3b8"
                fontSize="10"
              >
                {value.toFixed(0)}
              </text>
            );
          })}
        </svg>
      </div>
    );
  };

  // Render pie/doughnut chart
  const renderPieChart = () => {
    const { labels = [], datasets = [] } = data;
    if (!labels.length || !datasets.length) return renderNoData();

    const dataset = datasets[0];
    const total = dataset.data.reduce((a, b) => a + b, 0);
    const centerX = 200;
    const centerY = 150;
    const radius = type === 'doughnut' ? 60 : 80;
    const innerRadius = type === 'doughnut' ? 40 : 0;

    let startAngle = 0;

    return (
      <div className="chart-svg-container">
        <svg viewBox="0 0 400 300" preserveAspectRatio="xMidYMid meet">
          {/* Pie/doughnut segments */}
          {dataset.data.map((value, index) => {
            const percentage = value / total;
            const angle = percentage * 2 * Math.PI;
            const endAngle = startAngle + angle;

            const x1 = centerX + radius * Math.cos(startAngle);
            const y1 = centerY + radius * Math.sin(startAngle);
            const x2 = centerX + radius * Math.cos(endAngle);
            const y2 = centerY + radius * Math.sin(endAngle);

            const largeArcFlag = angle > Math.PI ? 1 : 0;

            // Outer path
            let path = `M ${centerX} ${centerY} L ${x1} ${y1} A ${radius} ${radius} 0 ${largeArcFlag} 1 ${x2} ${y2} Z`;

            // For doughnut, create a ring
            if (type === 'doughnut') {
              const innerX1 = centerX + innerRadius * Math.cos(startAngle);
              const innerY1 = centerY + innerRadius * Math.sin(startAngle);
              const innerX2 = centerX + innerRadius * Math.cos(endAngle);
              const innerY2 = centerY + innerRadius * Math.sin(endAngle);

              path = `M ${x1} ${y1} A ${radius} ${radius} 0 ${largeArcFlag} 1 ${x2} ${y2} L ${innerX2} ${innerY2} A ${innerRadius} ${innerRadius} 0 ${largeArcFlag} 0 ${innerX1} ${innerY1} Z`;
            }

            const color = dataset.backgroundColor?.[index] || getColor(index);

            startAngle = endAngle;

            return (
              <g key={`pie-${index}`}>
                <path
                  d={path}
                  fill={color}
                  stroke="#0a0c14"
                  strokeWidth="2"
                />
                {labels[index] && (
                  <title>{labels[index]}: {value} ({Math.round(percentage * 100)}%)</title>
                )}
              </g>
            );
          })}

          {/* Center text for doughnut */}
          {type === 'doughnut' && (
            <text
              x={centerX}
              y={centerY}
              textAnchor="middle"
              dominantBaseline="middle"
              fill="#d4af37"
              fontSize="16"
              fontWeight="bold"
            >
              {total}
            </text>
          )}
        </svg>

        {/* Legend */}
        <div className="chart-legend">
          {labels.map((label, index) => (
            <div key={`legend-${index}`} className="legend-item">
              <span
                className="legend-color"
                style={{ backgroundColor: dataset.backgroundColor?.[index] || getColor(index) }}
              ></span>
              <span className="legend-label">{label}</span>
            </div>
          ))}
        </div>
      </div>
    );
  };

  // Render radar chart
  const renderRadarChart = () => {
    const { labels = [], datasets = [] } = data;
    if (!labels.length || !datasets.length) return renderNoData();

    const centerX = 200;
    const centerY = 150;
    const radius = 100;
    const angleStep = (2 * Math.PI) / labels.length;

    return (
      <div className="chart-svg-container">
        <svg viewBox="0 0 400 300" preserveAspectRatio="xMidYMid meet">
          {/* Background circles */}
          {[0.25, 0.5, 0.75, 1].map(level => (
            <circle
              key={`bg-circle-${level}`}
              cx={centerX}
              cy={centerY}
              r={radius * level}
              fill="none"
              stroke="rgba(212, 175, 55, 0.1)"
              strokeWidth="1"
              strokeDasharray="5,5"
            />
          ))}

          {/* Axis lines */}
          {labels.map((_, index) => {
            const angle = index * angleStep - Math.PI / 2;
            const x = centerX + radius * Math.cos(angle);
            const y = centerY + radius * Math.sin(angle);
            return (
              <line
                key={`axis-${index}`}
                x1={centerX}
                y1={centerY}
                x2={x}
                y2={y}
                stroke="rgba(212, 175, 55, 0.1)"
                strokeWidth="1"
              />
            );
          })}

          {/* Data polygons */}
          {datasets.map((dataset, datasetIndex) => {
            const maxValue = Math.max(...dataset.data);
            const points = dataset.data.map((value, index) => {
              const angle = index * angleStep - Math.PI / 2;
              const distance = (value / maxValue) * radius;
              return {
                x: centerX + distance * Math.cos(angle),
                y: centerY + distance * Math.sin(angle)
              };
            });

            const polygonPath = points.map((p, i) => 
              `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`
            ).join(' ') + ' Z';

            return (
              <g key={`radar-${datasetIndex}`}>
                <path
                  d={polygonPath}
                  fill={dataset.backgroundColor || `${getColor(datasetIndex)}33`}
                  stroke={dataset.borderColor || getColor(datasetIndex)}
                  strokeWidth="2"
                />
              </g>
            );
          })}

          {/* Axis labels */}
          {labels.map((label, index) => {
            const angle = index * angleStep - Math.PI / 2;
            const x = centerX + (radius + 20) * Math.cos(angle);
            const y = centerY + (radius + 20) * Math.sin(angle);
            return (
              <text
                key={`label-${index}`}
                x={x}
                y={y}
                textAnchor="middle"
                dominantBaseline="middle"
                fill="#94a3b8"
                fontSize="12"
              >
                {label}
              </text>
            );
          })}
        </svg>
      </div>
    );
  };

  // Render no data state
  const renderNoData = () => (
    <div className="chart-empty" style={{ height }}>
      <span className="empty-icon">📊</span>
      <p>No data available</p>
    </div>
  );

  // Render loading state
  if (loading) {
    return (
      <div className="chart-loading" style={{ height }}>
        <div className="loading-spinner"></div>
        <p>Loading chart data...</p>
      </div>
    );
  }

  // Render based on chart type
  const renderChart = () => {
    switch (type) {
      case 'bar':
        return renderBarChart();
      case 'pie':
      case 'doughnut':
        return renderPieChart();
      case 'radar':
        return renderRadarChart();
      case 'line':
      default:
        return renderLineChart();
    }
  };

  return (
    <div className={`chart-container ${className}`} {...props}>
      {title && <h3 className="chart-title">{title}</h3>}
      {renderChart()}
    </div>
  );
};

// Predefined chart configurations (Now returning data only, not Chart.js config)
