// ===== src/Components/Layout/NavBar.jsx =====
import React, { useState, useEffect, useRef } from 'react';
import { Link, useLocation } from 'react-router-dom';

// Core imports
import { ROUTES } from '../../Config/Routes';
import { APP_CONFIG, STORAGE_KEYS } from '../../Utils/constants';
import Button from '../Common/Button';
import logo from '../../assets/CarEaselogo.jpeg';

// Style imports
import '../../Styles/Variables.css';
import '../../Styles/Global.css';
import '../../Styles/Buttons.css';
import '../../Styles/Responsive.css';
import '../../Styles/Layout.css';

const NavBar = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isServicesDropdownOpen, setIsServicesDropdownOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [cartCount, setCartCount] = useState(0);

  const location = useLocation();
  const dropdownRef = useRef(null);
  const searchRef = useRef(null);
  const navbarRef = useRef(null);

  // Handle scroll effect with throttle
  useEffect(() => {
    let timeoutId;
    const handleScroll = () => {
      if (timeoutId) return;
      timeoutId = setTimeout(() => {
        setIsScrolled(window.scrollY > 50);
        timeoutId = null;
      }, 10);
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => {
      window.removeEventListener('scroll', handleScroll);
      if (timeoutId) clearTimeout(timeoutId);
    };
  }, []);

  // Close menus on route change
  useEffect(() => {
    setIsMobileMenuOpen(false);
    setIsServicesDropdownOpen(false);
    setIsSearchOpen(false);
  }, [location]);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setIsServicesDropdownOpen(false);
      }
      if (searchRef.current && !searchRef.current.contains(event.target)) {
        setIsSearchOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Load cart count from storage
  useEffect(() => {
    const cart = JSON.parse(localStorage.getItem(STORAGE_KEYS.CART) || '[]');
    setCartCount(cart.length);
  }, []);

  // Handle escape key
  useEffect(() => {
    const handleEscape = (e) => {
      if (e.key === 'Escape') {
        setIsServicesDropdownOpen(false);
        setIsSearchOpen(false);
        setIsMobileMenuOpen(false);
      }
    };
    document.addEventListener('keydown', handleEscape);
    return () => document.removeEventListener('keydown', handleEscape);
  }, []);

  // Prevent body scroll when mobile menu is open
  useEffect(() => {
    if (isMobileMenuOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => {
      document.body.style.overflow = '';
    };
  }, [isMobileMenuOpen]);

  const isActive = (path) => {
    return location.pathname === path ? 'active' : '';
  };

  const isServicesActive = () => {
    const servicePaths = [
      ROUTES.SERVICES,
      ROUTES.RENTALS,
      ROUTES.CAR_WASH,
      ROUTES.REPAIRS,
      ROUTES.SALES
    ];
    return servicePaths.includes(location.pathname) ? 'active' : '';
  };

  const serviceLinks = [
    { path: ROUTES.RENTALS, label: 'Luxury Rentals', icon: '🚗', description: 'Exotic & luxury vehicles' },
    { path: ROUTES.CAR_WASH, label: 'Car Wash', icon: '🧼', description: 'Professional detailing' },
    { path: ROUTES.REPAIRS, label: 'Repairs', icon: '🔧', description: 'Expert maintenance' },
    { path: ROUTES.SALES, label: 'Sales', icon: '💰', description: 'Premium vehicles for sale' }
  ];

  const navLinks = [
    { path: ROUTES.HOME, label: 'Home', icon: '🏠' },
    { path: ROUTES.SERVICES, label: 'Services', icon: '🔧', hasDropdown: true },
    { path: ROUTES.ABOUT, label: 'About', icon: '📋' },
    { path: ROUTES.CONTACT, label: 'Contact', icon: '📞' }
  ];

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      window.location.href = `/search?q=${encodeURIComponent(searchQuery)}`;
    }
  };

  return (
    <>
      <nav 
        ref={navbarRef}
        className={`navbar ${isScrolled ? 'scrolled' : ''} ${isMobileMenuOpen ? 'mobile-open' : ''}`}
        aria-label="Main navigation"
      >
        {/* Background Effects */}
        <div className="navbar-bg"></div>
        <div className="navbar-glow"></div>
        <div className="navbar-particles"></div>

        <div className="navbar-container">
          {/* Logo with enhanced hover */}
          <Link 
            to={ROUTES.HOME} 
            className="navbar-logo" 
            onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
            aria-label={`${APP_CONFIG.name} Home`}
          >
            <div className="logo-wrapper">
              <img 
                src={logo} 
                alt={APP_CONFIG.name} 
                className="logo-image"
                loading="eager"
              />
              <span className="logo-text">CAR<span className="gold-text">EASE</span></span>
            </div>
            <div className="logo-glow"></div>
          </Link>

          {/* Desktop Search Bar */}
          <div className="desktop-search" ref={searchRef}>
            <form onSubmit={handleSearch} className="search-form">
              <input
                type="text"
                placeholder="Search vehicles..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="search-input"
                aria-label="Search"
              />
              <button type="submit" className="search-btn" aria-label="Submit search">
                <span className="search-icon">🔍</span>
              </button>
            </form>
          </div>

          {/* Desktop Actions */}
          <div className="desktop-actions">
            <button 
              className="icon-btn search-toggle" 
              onClick={() => setIsSearchOpen(!isSearchOpen)}
              aria-label="Toggle search"
            >
              <span className="icon">🔍</span>
            </button>
            <Link to="/wishlist" className="icon-btn" aria-label="Wishlist">
              <span className="icon">❤️</span>
              <span className="badge">0</span>
            </Link>
            <Link to="/cart" className="icon-btn" aria-label="Cart">
              <span className="icon">🛒</span>
              {cartCount > 0 && <span className="badge">{cartCount}</span>}
            </Link>
          </div>

          {/* Mobile Menu Button - Enhanced */}
          <button 
            className={`mobile-menu-btn ${isMobileMenuOpen ? 'active' : ''}`}
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            aria-label="Toggle navigation menu"
            aria-expanded={isMobileMenuOpen}
            aria-controls="main-navigation"
          >
            <span></span>
            <span></span>
            <span></span>
          </button>

          {/* Navigation Menu */}
          <div 
            id="main-navigation"
            className={`navbar-menu ${isMobileMenuOpen ? 'active' : ''}`}
          >
            {/* Mobile Search */}
            <div className="mobile-search">
              <form onSubmit={handleSearch} className="search-form">
                <input
                  type="text"
                  placeholder="Search vehicles..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="search-input"
                  autoFocus={isMobileMenuOpen}
                />
                <button type="submit" className="search-btn">🔍</button>
              </form>
            </div>

            {/* Navigation Links */}
            <ul className="nav-links">
              {navLinks.map((link) => (
                <li 
                  key={link.path} 
                  className={`nav-item ${link.hasDropdown ? 'has-dropdown' : ''}`}
                  ref={link.hasDropdown ? dropdownRef : null}
                >
                  {link.hasDropdown ? (
                    <>
                      <button
                        className={`nav-link ${isServicesActive()}`}
                        onClick={() => setIsServicesDropdownOpen(!isServicesDropdownOpen)}
                        aria-haspopup="true"
                        aria-expanded={isServicesDropdownOpen}
                      >
                        <span className="nav-link-icon">{link.icon}</span>
                        <span className="nav-link-text">{link.label}</span>
                        <span className={`dropdown-arrow ${isServicesDropdownOpen ? 'open' : ''}`}>▼</span>
                      </button>

                      {/* Enhanced Dropdown Menu */}
                      <div className={`services-dropdown ${isServicesDropdownOpen ? 'active' : ''}`}>
                        <div className="dropdown-header">
                          <h4 className="dropdown-title">Our Services</h4>
                          <p className="dropdown-subtitle">Choose from our premium offerings</p>
                        </div>
                        <div className="dropdown-grid">
                          {serviceLinks.map((service) => (
                            <Link
                              key={service.path}
                              to={service.path}
                              className={`dropdown-item ${isActive(service.path)}`}
                              onClick={() => {
                                window.scrollTo(0, 0);
                                setIsServicesDropdownOpen(false);
                                setIsMobileMenuOpen(false);
                              }}
                            >
                              <span className="dropdown-item-icon">{service.icon}</span>
                              <div className="dropdown-item-content">
                                <span className="dropdown-item-title">{service.label}</span>
                                <span className="dropdown-item-description">{service.description}</span>
                              </div>
                            </Link>
                          ))}
                        </div>
                      </div>
                    </>
                  ) : (
                    <Link 
                      to={link.path} 
                      className={`nav-link ${isActive(link.path)}`}
                      onClick={() => {
                        window.scrollTo(0, 0);
                        setIsMobileMenuOpen(false);
                      }}
                    >
                      <span className="nav-link-icon">{link.icon}</span>
                      <span className="nav-link-text">{link.label}</span>
                    </Link>
                  )}
                </li>
              ))}
            </ul>

            {/* Mobile Actions */}
            <div className="mobile-actions">
              <Link to="/wishlist" className="mobile-action-item">
                <span className="action-icon">❤️</span>
                <span className="action-label">Wishlist</span>
              </Link>
              <Link to="/cart" className="mobile-action-item">
                <span className="action-icon">🛒</span>
                <span className="action-label">Cart</span>
                {cartCount > 0 && <span className="action-badge">{cartCount}</span>}
              </Link>
            </div>

            {/* CTA Buttons */}
            <div className="navbar-actions">
              <Link to={ROUTES.ADMIN_LOGIN} className="admin-link">
                <span className="admin-link-icon">👤</span>
                <span className="admin-link-text">Admin</span>
              </Link>
              <Link to={ROUTES.BOOKING} className="book-btn-wrapper">
                <Button variant="primary" size="lg" className="book-btn">
                  <span className="btn-icon">📅</span>
                  <span className="btn-text">Book Now</span>
                </Button>
              </Link>
            </div>
          </div>
        </div>
      </nav>

      {/* Spacer with animation */}
      <div className={`navbar-spacer ${isScrolled ? 'scrolled' : ''}`}></div>

      {/* Floating Search Bar (mobile) */}
      {isSearchOpen && !isMobileMenuOpen && (
        <div className="floating-search" ref={searchRef}>
          <form onSubmit={handleSearch} className="floating-search-form">
            <input
              type="text"
              placeholder="Search vehicles..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="floating-search-input"
              autoFocus
            />
            <button type="submit" className="floating-search-btn">Search</button>
            <button 
              type="button" 
              className="floating-search-close"
              onClick={() => setIsSearchOpen(false)}
            >
              ×
            </button>
          </form>
        </div>
      )}
    </>
  );
};

export default NavBar;

// ===== src/Context/AdminAuthContext.jsx =====
import React, { createContext, useState, useContext, useCallback, useMemo, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useApp } from './AppContext';
import { adminLogin, verifyAdminToken, adminLogout } from '../Services/AdminService';
import { ROUTES } from '../Config/Routes';

// Create context
const AdminAuthContext = createContext(null);

/**
 * AdminAuthProvider Component - GOD MODE
 * Manages admin authentication state across the application
 */
export const AdminAuthProvider = ({ children }) => {
  const [admin, setAdmin] = useState(null);
  const [loading, setLoading] = useState(false);
  const [initializing, setInitializing] = useState(true);
  const [error, setError] = useState(null);
  const [permissions, setPermissions] = useState([]);
  const [sessionExpiry, setSessionExpiry] = useState(null);
  const [lastActivity, setLastActivity] = useState(Date.now());

  const navigate = useNavigate();
  const { addNotification } = useApp();

  // Check existing session on mount
  useEffect(() => {
    checkExistingSession();
  }, []);

  // Session expiry timer
  useEffect(() => {
    if (!sessionExpiry) return;

    const timeLeft = new Date(sessionExpiry) - new Date();
    if (timeLeft <= 0) {
      handleSessionExpiry();
      return;
    }

    const timer = setTimeout(() => {
      handleSessionExpiry();
    }, timeLeft);

    return () => clearTimeout(timer);
  }, [sessionExpiry]);

  // Activity tracking for auto-logout
  useEffect(() => {
    const events = ['mousedown', 'keydown', 'scroll', 'touchstart'];

    const handleActivity = () => {
      setLastActivity(Date.now());
    };

    events.forEach(event => {
      window.addEventListener(event, handleActivity);
    });

    return () => {
      events.forEach(event => {
        window.removeEventListener(event, handleActivity);
      });
    };
  }, []);

  // Auto-logout after 30 minutes of inactivity
  useEffect(() => {
    if (!admin) return;

    const inactivityTimeout = 30 * 60 * 1000; // 30 minutes
    const checkInactivity = setInterval(() => {
      if (Date.now() - lastActivity > inactivityTimeout) {
        handleInactivityLogout();
      }
    }, 60000); // Check every minute

    return () => clearInterval(checkInactivity);
  }, [admin, lastActivity]);

  const checkExistingSession = useCallback(async () => {
    setInitializing(true);
    try {
      const result = await verifyAdminToken();

      if (result.valid) {
        setAdmin(result.admin);
        setPermissions(result.permissions || []);
        setSessionExpiry(result.expiry);
      }
    } catch (err) {
      console.error('Session check failed:', err);
    } finally {
      setInitializing(false);
    }
  }, []);

  const handleSessionExpiry = useCallback(() => {
    setAdmin(null);
    setPermissions([]);
    setSessionExpiry(null);
    addNotification('Your session has expired. Please login again.', 'warning');
    navigate(ROUTES.ADMIN_LOGIN);
  }, [navigate, addNotification]);

  const handleInactivityLogout = useCallback(() => {
    setAdmin(null);
    setPermissions([]);
    setSessionExpiry(null);
    addNotification('You have been logged out due to inactivity.', 'warning');
    navigate(ROUTES.ADMIN_LOGIN);
  }, [navigate, addNotification]);

  /**
   * Admin login
   * @param {string} email - Admin email
   * @param {string} password - Admin password
   * @param {boolean} rememberMe - Remember me option
   */
  const login = useCallback(async (email, password, rememberMe = false) => {
    setLoading(true);
    setError(null);

    try {
      const result = await adminLogin(email, password);

      if (result.success) {
        setAdmin(result.admin);
        setPermissions(result.permissions || []);

        // Set session expiry
        const expiryDate = new Date();
        expiryDate.setTime(expiryDate.getTime() + (rememberMe ? 30 : 1) * 24 * 60 * 60 * 1000);
        setSessionExpiry(expiryDate);
        setLastActivity(Date.now());

        addNotification(`Welcome back, ${result.admin.name}!`, 'success');
        navigate(ROUTES.ADMIN_DASHBOARD);

        return result;
      }
    } catch (err) {
      setError(err.message);
      addNotification(err.message, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [navigate, addNotification]);

  /**
   * Admin logout
   */
  const logout = useCallback(async () => {
    setLoading(true);

    try {
      await adminLogout();

      setAdmin(null);
      setPermissions([]);
      setSessionExpiry(null);

      addNotification('Logged out successfully', 'info');
      navigate(ROUTES.ADMIN_LOGIN);
    } catch (err) {
      console.error('Logout error:', err);
    } finally {
      setLoading(false);
    }
  }, [navigate, addNotification]);

  /**
   * Check if admin has permission
   * @param {string} permission - Permission to check
   */
  const hasPermission = useCallback((permission) => {
    if (!admin) return false;
    return permissions.includes(permission);
  }, [admin, permissions]);

  /**
   * Check if admin has any of the given permissions
   * @param {Array} permissionList - List of permissions
   */
  const hasAnyPermission = useCallback((permissionList) => {
    if (!admin) return false;
    return permissionList.some(p => permissions.includes(p));
  }, [admin, permissions]);

  /**
   * Check if admin has all of the given permissions
   * @param {Array} permissionList - List of permissions
   */
  const hasAllPermissions = useCallback((permissionList) => {
    if (!admin) return false;
    return permissionList.every(p => permissions.includes(p));
  }, [admin, permissions]);

  /**
   * Check if admin has role
   * @param {string} role - Role to check
   */
  const hasRole = useCallback((role) => {
    if (!admin) return false;
    return admin.role === role;
  }, [admin]);

  /**
   * Refresh admin session
   */
  const refreshSession = useCallback(async () => {
    try {
      const result = await verifyAdminToken();

      if (result.valid) {
        setAdmin(result.admin);
        setPermissions(result.permissions || []);
        setSessionExpiry(result.expiry);
        setLastActivity(Date.now());
        return true;
      }

      return false;
    } catch (err) {
      console.error('Session refresh failed:', err);
      return false;
    }
  }, []);

  /**
   * Update admin profile
   * @param {Object} profileData - Profile data to update
   */
  const updateProfile = useCallback(async (profileData) => {
    setLoading(true);
    setError(null);

    try {
      // This would call an API to update profile
      setAdmin(prev => ({ ...prev, ...profileData }));
      addNotification('Profile updated successfully', 'success');
    } catch (err) {
      setError(err.message);
      addNotification(err.message, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [addNotification]);

  const value = useMemo(() => ({
    // State
    admin,
    loading,
    initializing,
    error,
    permissions,
    sessionExpiry,
    lastActivity,
    isAuthenticated: !!admin,
    isAdmin: hasRole('admin'),
    isSuperAdmin: hasRole('super_admin'),

    // Methods
    login,
    logout,
    hasPermission,
    hasAnyPermission,
    hasAllPermissions,
    hasRole,
    refreshSession,
    updateProfile,

    // Convenience aliases
    can: hasPermission,
    canAny: hasAnyPermission,
    canAll: hasAllPermissions
  }), [
    admin, loading, initializing, error, permissions, sessionExpiry,
    lastActivity, login, logout, hasPermission, hasAnyPermission,
    hasAllPermissions, hasRole, refreshSession, updateProfile
  ]);

  return (
    <AdminAuthContext.Provider value={value}>
      {children}
    </AdminAuthContext.Provider>
  );
};

/**
 * useAdminAuth Hook - Custom hook to use AdminAuthContext
 * @returns {Object} - Admin auth context value
 * @throws {Error} - If used outside of AdminAuthProvider
 */
export const useAdminAuth = () => {
  const context = useContext(AdminAuthContext);

  if (!context) {
    throw new Error('useAdminAuth must be used within an AdminAuthProvider');
  }

  return context;
};

export default AdminAuthContext;

