// ===== src/Context/AppContext.jsx =====
import React, { createContext, useState, useContext, useCallback, useMemo, useEffect } from 'react';

// Create context
const AppContext = createContext(null);

// Notification types
export const NOTIFICATION_TYPES = {
  SUCCESS: 'success',
  ERROR: 'error',
  WARNING: 'warning',
  INFO: 'info'
};

// Theme options
export const THEME_OPTIONS = {
  DARK: 'dark',
  LIGHT: 'light',
  SYSTEM: 'system'
};

/**
 * AppProvider Component - GOD MODE
 * Manages global application state
 */
export const AppProvider = ({ children }) => {
  // ===== STATE =====
  const [isLoading, setIsLoading] = useState(false);
  const [notifications, setNotifications] = useState([]);
  const [theme, setTheme] = useState(() => {
    const saved = localStorage.getItem('carease_theme');
    return saved || THEME_OPTIONS.DARK;
  });
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [modalStack, setModalStack] = useState([]);
  const [onlineStatus, setOnlineStatus] = useState(navigator.onLine);
  const [pageTitle, setPageTitle] = useState('CAR EASE');
  const [breadcrumbs, setBreadcrumbs] = useState([]);
  const [userPreferences, setUserPreferences] = useState(() => {
    const saved = localStorage.getItem('carease_preferences');
    return saved ? JSON.parse(saved) : {
      animations: true,
      compactMode: false,
      fontSize: 'medium',
      reducedMotion: false
    };
  });

  // ===== EFFECTS =====

  // Apply theme to document
  useEffect(() => {
    const root = document.documentElement;
    root.setAttribute('data-theme', theme);
    localStorage.setItem('carease_theme', theme);

    // Apply reduced motion if preference set
    if (userPreferences.reducedMotion) {
      root.setAttribute('data-reduced-motion', 'true');
    } else {
      root.removeAttribute('data-reduced-motion');
    }
  }, [theme, userPreferences.reducedMotion]);

  // Online/Offline detection
  useEffect(() => {
    const handleOnline = () => setOnlineStatus(true);
    const handleOffline = () => {
      setOnlineStatus(false);
      addNotification('You are offline. Some features may be unavailable.', NOTIFICATION_TYPES.WARNING);
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Save preferences to localStorage
  useEffect(() => {
    localStorage.setItem('carease_preferences', JSON.stringify(userPreferences));
  }, [userPreferences]);

  // ===== NOTIFICATION METHODS =====

  /**
   * Add a notification
   * @param {string} message - Notification message
   * @param {string} type - Notification type
   * @param {number} duration - Auto-close duration (ms), 0 for no auto-close
   * @returns {string} - Notification ID
   */
  const addNotification = useCallback((message, type = NOTIFICATION_TYPES.INFO, duration = 5000) => {
    const id = `notification-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

    const notification = {
      id,
      message,
      type,
      duration,
      timestamp: Date.now(),
      read: false
    };

    setNotifications(prev => [notification, ...prev]);

    // Auto-remove after duration
    if (duration > 0) {
      setTimeout(() => {
        removeNotification(id);
      }, duration);
    }

    return id;
  }, []);

  /**
   * Remove a notification
   * @param {string} id - Notification ID
   */
  const removeNotification = useCallback((id) => {
    setNotifications(prev => prev.filter(notif => notif.id !== id));
  }, []);

  /**
   * Clear all notifications
   */
  const clearNotifications = useCallback(() => {
    setNotifications([]);
  }, []);

  /**
   * Mark notification as read
   * @param {string} id - Notification ID
   */
  const markAsRead = useCallback((id) => {
    setNotifications(prev => prev.map(notif =>
      notif.id === id ? { ...notif, read: true } : notif
    ));
  }, []);

  /**
   * Mark all notifications as read
   */
  const markAllAsRead = useCallback(() => {
    setNotifications(prev => prev.map(notif => ({ ...notif, read: true })));
  }, []);

  // ===== MODAL METHODS =====

  /**
   * Open a modal
   * @param {string} id - Modal ID
   * @param {Object} props - Modal props
   */
  const openModal = useCallback((id, props = {}) => {
    setModalStack(prev => [...prev, { id, props, timestamp: Date.now() }]);
  }, []);

  /**
   * Close a modal
   * @param {string} id - Modal ID
   */
  const closeModal = useCallback((id) => {
    setModalStack(prev => prev.filter(modal => modal.id !== id));
  }, []);

  /**
   * Close the top modal
   */
  const closeTopModal = useCallback(() => {
    setModalStack(prev => prev.slice(0, -1));
  }, []);

  /**
   * Close all modals
   */
  const closeAllModals = useCallback(() => {
    setModalStack([]);
  }, []);

  // ===== PREFERENCES METHODS =====

  /**
   * Update user preferences
   * @param {Object} newPreferences - New preferences
   */
  const updatePreferences = useCallback((newPreferences) => {
    setUserPreferences(prev => ({
      ...prev,
      ...newPreferences
    }));
  }, []);

  /**
   * Toggle theme
   */
  const toggleTheme = useCallback(() => {
    setTheme(prev => prev === THEME_OPTIONS.DARK ? THEME_OPTIONS.LIGHT : THEME_OPTIONS.DARK);
  }, []);

  /**
   * Toggle sidebar
   */
  const toggleSidebar = useCallback(() => {
    setSidebarCollapsed(prev => !prev);
  }, []);

  // ===== BREADCRUMB METHODS =====

  /**
   * Set breadcrumbs
   * @param {Array} items - Breadcrumb items
   */
  const setBreadcrumbItems = useCallback((items) => {
    setBreadcrumbs(items);
  }, []);

  /**
   * Add breadcrumb item
   * @param {Object} item - Breadcrumb item
   */
  const addBreadcrumbItem = useCallback((item) => {
    setBreadcrumbs(prev => [...prev, item]);
  }, []);

  /**
   * Clear breadcrumbs
   */
  const clearBreadcrumbs = useCallback(() => {
    setBreadcrumbs([]);
  }, []);

  // ===== COMPUTED PROPERTIES =====

  // Unread notifications count
  const unreadCount = useMemo(() => {
    return notifications.filter(n => !n.read).length;
  }, [notifications]);

  // Current modal
  const currentModal = useMemo(() => {
    return modalStack[modalStack.length - 1] || null;
  }, [modalStack]);

  // Is any modal open
  const isModalOpen = useMemo(() => {
    return modalStack.length > 0;
  }, [modalStack]);

  // Context value
  const value = useMemo(() => ({
    // State
    isLoading,
    setIsLoading,
    notifications,
    theme,
    sidebarCollapsed,
    modalStack,
    onlineStatus,
    pageTitle,
    breadcrumbs,
    userPreferences,
    unreadCount,
    currentModal,
    isModalOpen,

    // Notification methods
    addNotification,
    removeNotification,
    clearNotifications,
    markAsRead,
    markAllAsRead,

    // Modal methods
    openModal,
    closeModal,
    closeTopModal,
    closeAllModals,

    // Preference methods
    setTheme,
    toggleTheme,
    toggleSidebar,
    updatePreferences,

    // Breadcrumb methods
    setPageTitle,
    setBreadcrumbItems,
    addBreadcrumbItem,
    clearBreadcrumbs,

    // Helper methods
    isOnline: onlineStatus,
    isOffline: !onlineStatus
  }), [
    isLoading, notifications, theme, sidebarCollapsed, modalStack,
    onlineStatus, pageTitle, breadcrumbs, userPreferences, unreadCount,
    currentModal, isModalOpen, addNotification, removeNotification,
    clearNotifications, markAsRead, markAllAsRead, openModal, closeModal,
    closeTopModal, closeAllModals, toggleTheme, toggleSidebar,
    updatePreferences, setBreadcrumbItems, addBreadcrumbItem,
    clearBreadcrumbs, setPageTitle
  ]);

  return (
    <AppContext.Provider value={value}>
      {children}
    </AppContext.Provider>
  );
};

/**
 * useApp Hook - Custom hook to use AppContext
 * @returns {Object} - App context value
 * @throws {Error} - If used outside of AppProvider
 */
export const useApp = () => {
  const context = useContext(AppContext);

  if (!context) {
    throw new Error('useApp must be used within an AppProvider');
  }

  return context;
};

// Convenience hooks for specific features
export const useNotifications = () => {
  const { notifications, addNotification, removeNotification, clearNotifications, unreadCount } = useApp();
  return { notifications, addNotification, removeNotification, clearNotifications, unreadCount };
};

export const useModals = () => {
  const { openModal, closeModal, closeTopModal, closeAllModals, currentModal, isModalOpen } = useApp();
  return { openModal, closeModal, closeTopModal, closeAllModals, currentModal, isModalOpen };
};

export const useTheme = () => {
  const { theme, setTheme, toggleTheme, userPreferences, updatePreferences } = useApp();
  return { theme, setTheme, toggleTheme, userPreferences, updatePreferences };
};

export default AppContext;

// ===== src/Context/BookingContext.jsx =====
import React, { createContext, useState, useContext, useCallback, useMemo } from 'react';
import { useApp } from './AppContext';
import { createBooking, getBookingById, getUserBookings, cancelBooking } from '../Services/BookingService';

// Create context
const BookingContext = createContext(null);

/**
 * BookingProvider Component - GOD MODE
 * Manages booking state across the application
 */
export const BookingProvider = ({ children }) => {
  const [currentBooking, setCurrentBooking] = useState(null);
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [filters, setFilters] = useState({
    status: 'all',
    dateRange: null,
    serviceType: 'all',
    search: ''
  });
  const [pagination, setPagination] = useState({
    page: 1,
    limit: 10,
    total: 0,
    totalPages: 0
  });

  const { addNotification } = useApp();

  /**
   * Fetch user bookings
   * @param {string} userEmail - User email
   * @param {Object} options - Fetch options
   */
  const fetchUserBookings = useCallback(async (userEmail, options = {}) => {
    if (!userEmail) return;

    setLoading(true);
    setError(null);

    try {
      const result = await getUserBookings(userEmail, {
        page: options.page || pagination.page,
        limit: options.limit || pagination.limit,
        ...filters,
        ...options
      });

      setBookings(result.bookings || []);
      setPagination({
        page: result.page || 1,
        limit: result.limit || 10,
        total: result.total || 0,
        totalPages: result.totalPages || 0
      });
    } catch (err) {
      setError(err.message);
      addNotification(err.message, 'error');
    } finally {
      setLoading(false);
    }
  }, [filters, pagination.page, pagination.limit, addNotification]);

  /**
   * Fetch booking by ID
   * @param {string} bookingId - Booking ID
   */
  const fetchBooking = useCallback(async (bookingId) => {
    if (!bookingId) return;

    setLoading(true);
    setError(null);

    try {
      const booking = await getBookingById(bookingId);
      setCurrentBooking(booking);
      return booking;
    } catch (err) {
      setError(err.message);
      addNotification(err.message, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [addNotification]);

  /**
   * Create a new booking
   * @param {Object} bookingData - Booking data
   */
  const createNewBooking = useCallback(async (bookingData) => {
    setLoading(true);
    setError(null);

    try {
      const result = await createBooking(bookingData);

      if (result.success) {
        setCurrentBooking(result.booking);
        setBookings(prev => [result.booking, ...prev]);
        addNotification('Booking created successfully!', 'success');
        return result.booking;
      }
    } catch (err) {
      setError(err.message);
      addNotification(err.message, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [addNotification]);

  /**
   * Cancel a booking
   * @param {string} bookingId - Booking ID
   * @param {string} reason - Cancellation reason
   */
  const cancelExistingBooking = useCallback(async (bookingId, reason = '') => {
    setLoading(true);
    setError(null);

    try {
      const result = await cancelBooking(bookingId, reason);

      if (result.success) {
        // Update in bookings list
        setBookings(prev => prev.map(b => 
          b.id === bookingId ? { ...b, status: 'cancelled' } : b
        ));

        // Update current booking if it's the one being cancelled
        if (currentBooking?.id === bookingId) {
          setCurrentBooking(prev => ({ ...prev, status: 'cancelled' }));
        }

        addNotification('Booking cancelled successfully', 'success');
        return result;
      }
    } catch (err) {
      setError(err.message);
      addNotification(err.message, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [currentBooking, addNotification]);

  /**
   * Update filters
   * @param {Object} newFilters - New filter values
   */
  const updateFilters = useCallback((newFilters) => {
    setFilters(prev => ({ ...prev, ...newFilters }));
    setPagination(prev => ({ ...prev, page: 1 })); // Reset to first page on filter change
  }, []);

  /**
   * Clear all filters
   */
  const clearFilters = useCallback(() => {
    setFilters({
      status: 'all',
      dateRange: null,
      serviceType: 'all',
      search: ''
    });
    setPagination(prev => ({ ...prev, page: 1 }));
  }, []);

  /**
   * Change page
   * @param {number} page - Page number
   */
  const changePage = useCallback((page) => {
    setPagination(prev => ({ ...prev, page }));
  }, []);

  /**
   * Change items per page
   * @param {number} limit - Items per page
   */
  const changeLimit = useCallback((limit) => {
    setPagination(prev => ({ ...prev, limit, page: 1 }));
  }, []);

  /**
   * Clear current booking
   */
  const clearCurrentBooking = useCallback(() => {
    setCurrentBooking(null);
  }, []);

  // Filtered and sorted bookings
  const filteredBookings = useMemo(() => {
    if (!bookings.length) return [];

    return bookings.filter(booking => {
      // Filter by status
      if (filters.status !== 'all' && booking.status !== filters.status) {
        return false;
      }

      // Filter by service type
      if (filters.serviceType !== 'all' && booking.serviceType !== filters.serviceType) {
        return false;
      }

      // Filter by search
      if (filters.search) {
        const searchLower = filters.search.toLowerCase();
        return (
          booking.id?.toLowerCase().includes(searchLower) ||
          booking.serviceType?.toLowerCase().includes(searchLower) ||
          booking.location?.toLowerCase().includes(searchLower)
        );
      }

      // Filter by date range
      if (filters.dateRange) {
        const bookingDate = new Date(booking.date);
        const startDate = new Date(filters.dateRange.start);
        const endDate = new Date(filters.dateRange.end);

        if (bookingDate < startDate || bookingDate > endDate) {
          return false;
        }
      }

      return true;
    });
  }, [bookings, filters]);

  // Booking statistics
  const stats = useMemo(() => {
    const total = bookings.length;
    const confirmed = bookings.filter(b => b.status === 'confirmed').length;
    const pending = bookings.filter(b => b.status === 'pending').length;
    const completed = bookings.filter(b => b.status === 'completed').length;
    const cancelled = bookings.filter(b => b.status === 'cancelled').length;

    const totalSpent = bookings
      .filter(b => b.status === 'completed')
      .reduce((sum, b) => sum + (b.totalPrice || 0), 0);

    const upcoming = bookings.filter(b => 
      b.status === 'confirmed' && new Date(b.date) > new Date()
    ).length;

    return {
      total,
      confirmed,
      pending,
      completed,
      cancelled,
      totalSpent,
      upcoming
    };
  }, [bookings]);

  const value = useMemo(() => ({
    // State
    currentBooking,
    bookings,
    filteredBookings,
    loading,
    error,
    filters,
    pagination,
    stats,

    // Methods
    fetchUserBookings,
    fetchBooking,
    createNewBooking,
    cancelExistingBooking,
    updateFilters,
    clearFilters,
    changePage,
    changeLimit,
    clearCurrentBooking,
    setBookings
  }), [
    currentBooking, bookings, filteredBookings, loading, error,
    filters, pagination, stats, fetchUserBookings, fetchBooking,
    createNewBooking, cancelExistingBooking, updateFilters,
    clearFilters, changePage, changeLimit, clearCurrentBooking
  ]);

  return (
    <BookingContext.Provider value={value}>
      {children}
    </BookingContext.Provider>
  );
};

/**
 * useBookingContext Hook - Custom hook to use BookingContext
 * @returns {Object} - Booking context value
 * @throws {Error} - If used outside of BookingProvider
 */
export const useBookingContext = () => {
  const context = useContext(BookingContext);

  if (!context) {
    throw new Error('useBookingContext must be used within a BookingProvider');
  }

  return context;
};

export default BookingContext;

