import { useState, useCallback, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { adminLogin, verifyAdminToken, adminLogout } from '../Services/AdminService';
import { ROUTES } from '../Config/Routes';
import { useApp } from '../Context/AppContext';

/**
 * useAdminAuth Hook - GOD MODE
 * Comprehensive admin authentication hook
 * 
 * @returns {Object} - Admin auth state and methods
 */
const useAdminAuth = () => {
  const [admin, setAdmin] = useState(null);
  const [loading, setLoading] = useState(false);
  const [initializing, setInitializing] = useState(true);
  const [error, setError] = useState(null);
  const [permissions, setPermissions] = useState([]);
  const [sessionExpiry, setSessionExpiry] = useState(null);

  const navigate = useNavigate();
  const { addNotification } = useApp();

  // Check existing session on mount
  useEffect(() => {
    checkExistingSession();
  }, []);

  // Session expiry timer
  useEffect(() => {
    if (!sessionExpiry) return;

    const timeLeft = new Date(sessionExpiry) - new Date();
    if (timeLeft <= 0) {
      handleSessionExpiry();
      return;
    }

    const timer = setTimeout(() => {
      handleSessionExpiry();
    }, timeLeft);

    return () => clearTimeout(timer);
  }, [sessionExpiry]);

  const checkExistingSession = useCallback(async () => {
    setInitializing(true);
    try {
      const result = await verifyAdminToken();

      if (result.valid) {
        setAdmin(result.admin);
        setPermissions(result.permissions || []);
        setSessionExpiry(result.expiry);
      }
    } catch (err) {
      console.error('Session check failed:', err);
    } finally {
      setInitializing(false);
    }
  }, []);

  const handleSessionExpiry = useCallback(() => {
    setAdmin(null);
    setPermissions([]);
    setSessionExpiry(null);
    addNotification('Your session has expired. Please login again.', 'warning');
    navigate(ROUTES.ADMIN_LOGIN);
  }, [navigate, addNotification]);

  // Login
  const login = useCallback(async (email, password, rememberMe = false) => {
    setLoading(true);
    setError(null);

    try {
      const result = await adminLogin(email, password);

      if (result.success) {
        setAdmin(result.admin);
        setPermissions(result.permissions || []);

        // Set session expiry (24 hours by default, 30 days if remember me)
        const expiryDate = new Date();
        expiryDate.setTime(expiryDate.getTime() + (rememberMe ? 30 : 1) * 24 * 60 * 60 * 1000);
        setSessionExpiry(expiryDate);

        addNotification(`Welcome back, ${result.admin.name}!`, 'success');
        navigate(ROUTES.ADMIN_DASHBOARD);

        return result;
      }
    } catch (err) {
      setError(err.message);
      addNotification(err.message, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [navigate, addNotification]);

  // Logout
  const logout = useCallback(async () => {
    setLoading(true);

    try {
      await adminLogout();

      setAdmin(null);
      setPermissions([]);
      setSessionExpiry(null);

      addNotification('Logged out successfully', 'info');
      navigate(ROUTES.ADMIN_LOGIN);
    } catch (err) {
      console.error('Logout error:', err);
    } finally {
      setLoading(false);
    }
  }, [navigate, addNotification]);

  // Check permission
  const hasPermission = useCallback((permission) => {
    if (!admin) return false;
    return permissions.includes(permission);
  }, [admin, permissions]);

  // Check role
  const hasRole = useCallback((role) => {
    if (!admin) return false;
    return admin.role === role;
  }, [admin]);

  // Check any permission
  const hasAnyPermission = useCallback((permissionList) => {
    if (!admin) return false;
    return permissionList.some(p => permissions.includes(p));
  }, [admin, permissions]);

  // Check all permissions
  const hasAllPermissions = useCallback((permissionList) => {
    if (!admin) return false;
    return permissionList.every(p => permissions.includes(p));
  }, [admin, permissions]);

  // Refresh session
  const refreshSession = useCallback(async () => {
    try {
      const result = await verifyAdminToken();

      if (result.valid) {
        setAdmin(result.admin);
        setPermissions(result.permissions || []);
        setSessionExpiry(result.expiry);
        return true;
      }

      return false;
    } catch (err) {
      console.error('Session refresh failed:', err);
      return false;
    }
  }, []);

  // Update admin profile
  const updateProfile = useCallback(async (profileData) => {
    setLoading(true);
    setError(null);

    try {
      // This would call an API to update profile
      setAdmin(prev => ({ ...prev, ...profileData }));
      addNotification('Profile updated successfully', 'success');
    } catch (err) {
      setError(err.message);
      addNotification(err.message, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [addNotification]);

  return {
    // State
    admin,
    loading,
    initializing,
    error,
    permissions,
    sessionExpiry,
    isAuthenticated: !!admin,
    isAdmin: hasRole('admin'),
    isSuperAdmin: hasRole('super_admin'),

    // Methods
    login,
    logout,
    hasPermission,
    hasRole,
    hasAnyPermission,
    hasAllPermissions,
    refreshSession,
    updateProfile,

    // Helpers
    can: hasPermission,
    canAny: hasAnyPermission,
    canAll: hasAllPermissions
  };
};

export default useAdminAuth;

// ===== src/Hooks/useAuth.js =====
import { useState, useCallback, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  login,
  register,
  logout,
  getCurrentUser,
  isAuthenticated,
  updateProfile,
  changePassword
} from '../Services/auth.service';
import { ROUTES } from '../Config/Routes';
import { useApp } from '../Context/AppContext';

/**
 * useAuth Hook - GOD MODE
 * Comprehensive user authentication hook
 * 
 * @returns {Object} - Auth state and methods
 */
const useAuth = () => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(false);
  const [initializing, setInitializing] = useState(true);
  const [error, setError] = useState(null);

  const navigate = useNavigate();
  const { addNotification } = useApp();

  // Check existing session on mount
  useEffect(() => {
    checkAuth();
  }, []);

  const checkAuth = useCallback(() => {
    const currentUser = getCurrentUser();
    const authenticated = isAuthenticated();

    if (authenticated && currentUser) {
      setUser(currentUser);
    }

    setInitializing(false);
  }, []);

  // Handle login
  const handleLogin = useCallback(async (email, password, rememberMe = false) => {
    setLoading(true);
    setError(null);

    try {
      const result = await login(email, password, rememberMe);

      if (result.success) {
        setUser(result.user);
        addNotification(`Welcome back, ${result.user.firstName}!`, 'success');
        navigate(ROUTES.HOME);
        return result;
      }
    } catch (err) {
      setError(err.message);
      addNotification(err.message, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [navigate, addNotification]);

  // Handle register
  const handleRegister = useCallback(async (userData) => {
    setLoading(true);
    setError(null);

    try {
      const result = await register(userData);

      if (result.success) {
        setUser(result.user);
        addNotification('Registration successful! Please check your email to verify your account.', 'success');
        navigate(ROUTES.HOME);
        return result;
      }
    } catch (err) {
      setError(err.message);
      addNotification(err.message, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [navigate, addNotification]);

  // Handle logout
  const handleLogout = useCallback(async () => {
    setLoading(true);

    try {
      await logout();
      setUser(null);
      addNotification('Logged out successfully', 'info');
      navigate(ROUTES.HOME);
    } catch (err) {
      console.error('Logout error:', err);
    } finally {
      setLoading(false);
    }
  }, [navigate, addNotification]);

  // Update profile
  const handleUpdateProfile = useCallback(async (profileData) => {
    setLoading(true);
    setError(null);

    try {
      const updatedUser = await updateProfile(profileData);
      setUser(updatedUser);
      addNotification('Profile updated successfully', 'success');
      return updatedUser;
    } catch (err) {
      setError(err.message);
      addNotification(err.message, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [addNotification]);

  // Change password
  const handleChangePassword = useCallback(async (currentPassword, newPassword) => {
    setLoading(true);
    setError(null);

    try {
      await changePassword(currentPassword, newPassword);
      addNotification('Password changed successfully', 'success');
    } catch (err) {
      setError(err.message);
      addNotification(err.message, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [addNotification]);

  return {
    // State
    user,
    loading,
    initializing,
    error,
    isAuthenticated: !!user,

    // Methods
    login: handleLogin,
    register: handleRegister,
    logout: handleLogout,
    updateProfile: handleUpdateProfile,
    changePassword: handleChangePassword,

    // User info
    isAdmin: user?.role === 'admin',
    isSuperAdmin: user?.role === 'super_admin',
    isProvider: user?.role === 'provider',
    isCustomer: user?.role === 'customer'
  };
};

export default useAuth;

// ===== src/Hooks/useLocation.js =====
import { useState, useEffect, useCallback, useRef } from 'react';
import { getCurrentLocation, geocodeAddress, reverseGeocode, trackDelivery } from '../Services/LocationService';

/**
 * useLocation Hook - GOD MODE
 * Comprehensive location management hook
 * 
 * @param {Object} options - Configuration options
 * @returns {Object} - Location state and methods
 */
const useLocation = (options = {}) => {
  const {
    autoTrack = false,
    watchPosition = false,
    highAccuracy = true,
    timeout = 10000,
    maximumAge = 0
  } = options;

  const [currentLocation, setCurrentLocation] = useState(null);
  const [address, setAddress] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [permission, setPermission] = useState(null);
  const [watchId, setWatchId] = useState(null);
  const [trackingDelivery, setTrackingDelivery] = useState(null);
  const [deliveryUpdate, setDeliveryUpdate] = useState(null);

  const watchRef = useRef(null);

  // Check permission on mount
  useEffect(() => {
    checkPermission();

    return () => {
      if (watchRef.current) {
        navigator.geolocation.clearWatch(watchRef.current);
      }
    };
  }, []);

  // Auto track if enabled
  useEffect(() => {
    if (autoTrack) {
      startTracking();
    } else {
      stopTracking();
    }
  }, [autoTrack]);

  // Check location permission
  const checkPermission = useCallback(async () => {
    if (!navigator.permissions) {
      setPermission('unknown');
      return;
    }

    try {
      const result = await navigator.permissions.query({ name: 'geolocation' });
      setPermission(result.state);

      result.addEventListener('change', () => {
        setPermission(result.state);
      });
    } catch (err) {
      console.error('Permission check failed:', err);
      setPermission('unknown');
    }
  }, []);

  // Get current location
  const getLocation = useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      const location = await getCurrentLocation({
        enableHighAccuracy: highAccuracy,
        timeout,
        maximumAge
      });

      setCurrentLocation(location);

      // Reverse geocode to get address
      try {
        const addressData = await reverseGeocode(location.lat, location.lng);
        setAddress(addressData);
      } catch (geoErr) {
        console.warn('Reverse geocoding failed:', geoErr);
      }

      return location;
    } catch (err) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  }, [highAccuracy, timeout, maximumAge]);

  // Start watching position
  const startTracking = useCallback(() => {
    if (!navigator.geolocation) {
      setError('Geolocation not supported');
      return;
    }

    if (watchRef.current) {
      navigator.geolocation.clearWatch(watchRef.current);
    }

    watchRef.current = navigator.geolocation.watchPosition(
      (position) => {
        const location = {
          lat: position.coords.latitude,
          lng: position.coords.longitude,
          accuracy: position.coords.accuracy,
          timestamp: position.timestamp
        };
        setCurrentLocation(location);
        setError(null);
      },
      (err) => {
        setError(err.message);
      },
      {
        enableHighAccuracy: highAccuracy,
        timeout,
        maximumAge
      }
    );

    setWatchId(watchRef.current);
  }, [highAccuracy, timeout, maximumAge]);

  // Stop watching position
  const stopTracking = useCallback(() => {
    if (watchRef.current) {
      navigator.geolocation.clearWatch(watchRef.current);
      watchRef.current = null;
      setWatchId(null);
    }
  }, []);

  // Search address
  const searchAddress = useCallback(async (query) => {
    setLoading(true);
    setError(null);

    try {
      const results = await geocodeAddress(query);
      return results;
    } catch (err) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  }, []);

  // Get address from coordinates
  const getAddressFromCoords = useCallback(async (lat, lng) => {
    setLoading(true);
    setError(null);

    try {
      const addressData = await reverseGeocode(lat, lng);
      setAddress(addressData);
      return addressData;
    } catch (err) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  }, []);

  // Calculate distance between two points
  const calculateDistance = useCallback((point1, point2, unit = 'km') => {
    const toRad = (value) => value * Math.PI / 180;

    const R = unit === 'km' ? 6371 : 3959;
    const dLat = toRad(point2.lat - point1.lat);
    const dLon = toRad(point2.lng - point1.lng);

    const a = 
      Math.sin(dLat / 2) * Math.sin(dLat / 2) +
      Math.cos(toRad(point1.lat)) * Math.cos(toRad(point2.lat)) * 
      Math.sin(dLon / 2) * Math.sin(dLon / 2);

    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    const distance = R * c;

    return Math.round(distance * 100) / 100;
  }, []);

  // Track delivery in real-time
  const trackDeliveryStatus = useCallback((deliveryId) => {
    if (trackingDelivery) {
      trackingDelivery();
    }

    setLoading(true);

    try {
      const unsubscribe = trackDelivery(deliveryId, (update) => {
        setDeliveryUpdate(update);
        setLoading(false);
      });

      setTrackingDelivery(() => unsubscribe);
      return unsubscribe;
    } catch (err) {
      setError(err.message);
      setLoading(false);
      throw err;
    }
  }, [trackingDelivery]);

  // Stop tracking delivery
  const stopTrackingDelivery = useCallback(() => {
    if (trackingDelivery) {
      trackingDelivery();
      setTrackingDelivery(null);
      setDeliveryUpdate(null);
    }
  }, [trackingDelivery]);

  // Clear location
  const clearLocation = useCallback(() => {
    setCurrentLocation(null);
    setAddress(null);
    setError(null);
  }, []);

  return {
    // State
    currentLocation,
    address,
    loading,
    error,
    permission,
    watchId,
    isWatching: !!watchId,
    deliveryUpdate,
    isTrackingDelivery: !!trackingDelivery,

    // Methods
    getLocation,
    startTracking,
    stopTracking,
    searchAddress,
    getAddressFromCoords,
    calculateDistance,
    trackDeliveryStatus,
    stopTrackingDelivery,
    clearLocation,

    // Helpers
    hasPermission: permission === 'granted'
  };
};

export default useLocation;

// ===== src/Hooks/usePayment.js =====
import { useState, useCallback, useMemo } from 'react';
import { processPayment, getPaymentStatus, processRefund } from '../Services/PaymentService';
import { useApp } from '../Context/AppContext';

/**
 * usePayment Hook - GOD MODE
 * Comprehensive payment management hook
 * 
 * @param {Object} initialConfig - Initial payment configuration
 * @returns {Object} - Payment state and methods
 */
const usePayment = (initialConfig = {}) => {
  const [payment, setPayment] = useState(null);
  const [payments, setPayments] = useState([]);
  const [loading, setLoading] = useState(false);
  const [processing, setProcessing] = useState(false);
  const [error, setError] = useState(null);
  const [selectedMethod, setSelectedMethod] = useState('card');
  const [transactionStatus, setTransactionStatus] = useState(null);
  const [refundStatus, setRefundStatus] = useState(null);

  const { addNotification } = useApp();

  // Process new payment
  const processNewPayment = useCallback(async (paymentData, gateway = 'stripe') => {
    setProcessing(true);
    setError(null);
    setTransactionStatus('processing');

    try {
      const result = await processPayment(paymentData, gateway);

      if (result.success) {
        setPayment(result);
        setTransactionStatus('success');
        addNotification('Payment processed successfully!', 'success');

        // Add to payments list
        setPayments(prev => [{
          id: result.transactionId,
          amount: result.amount,
          status: 'completed',
          date: new Date().toISOString(),
          method: gateway,
          ...result
        }, ...prev]);

        return result;
      } else {
        throw new Error('Payment failed');
      }
    } catch (err) {
      setError(err.message);
      setTransactionStatus('failed');
      addNotification(err.message, 'error');
      throw err;
    } finally {
      setProcessing(false);
    }
  }, [addNotification]);

  // Verify payment status
  const verifyPayment = useCallback(async (transactionId) => {
    setLoading(true);
    setError(null);

    try {
      const status = await getPaymentStatus(transactionId);
      setTransactionStatus(status);

      // Update payment in list
      setPayments(prev => prev.map(p => 
        p.id === transactionId ? { ...p, status: status.status } : p
      ));

      return status;
    } catch (err) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  }, []);

  // Process refund
  const processPaymentRefund = useCallback(async (transactionId, amount, reason = '') => {
    setLoading(true);
    setError(null);
    setRefundStatus('processing');

    try {
      const result = await processRefund({
        transactionId,
        amount,
        reason
      });

      if (result.success) {
        setRefundStatus('completed');
        addNotification('Refund processed successfully', 'success');

        // Update payment status
        setPayments(prev => prev.map(p => 
          p.id === transactionId ? { ...p, status: 'refunded', refundId: result.refundId } : p
        ));

        return result;
      }
    } catch (err) {
      setError(err.message);
      setRefundStatus('failed');
      addNotification(err.message, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [addNotification]);

  // Calculate payment summary
  const summary = useMemo(() => {
    const total = payments.reduce((sum, p) => sum + (p.amount || 0), 0);
    const completed = payments.filter(p => p.status === 'completed').length;
    const pending = payments.filter(p => p.status === 'pending').length;
    const failed = payments.filter(p => p.status === 'failed').length;
    const refunded = payments.filter(p => p.status === 'refunded').length;

    const totalCompleted = payments
      .filter(p => p.status === 'completed')
      .reduce((sum, p) => sum + p.amount, 0);

    const totalRefunded = payments
      .filter(p => p.status === 'refunded')
      .reduce((sum, p) => sum + p.amount, 0);

    return {
      total,
      completed,
      pending,
      failed,
      refunded,
      totalCompleted,
      totalRefunded,
      count: payments.length
    };
  }, [payments]);

  // Get payments by method
  const getPaymentsByMethod = useCallback((method) => {
    return payments.filter(p => p.method === method);
  }, [payments]);

  // Get recent payments
  const getRecentPayments = useCallback((limit = 5) => {
    return payments.slice(0, limit);
  }, [payments]);

  // Clear payment state
  const clearPayment = useCallback(() => {
    setPayment(null);
    setError(null);
    setTransactionStatus(null);
    setRefundStatus(null);
  }, []);

  // Clear all payments
  const clearAllPayments = useCallback(() => {
    setPayments([]);
    clearPayment();
  }, [clearPayment]);

  return {
    // State
    payment,
    payments,
    loading,
    processing,
    error,
    selectedMethod,
    transactionStatus,
    refundStatus,
    summary,

    // Methods
    processNewPayment,
    verifyPayment,
    processPaymentRefund,
    getPaymentsByMethod,
    getRecentPayments,
    clearPayment,
    clearAllPayments,
    setSelectedMethod,
    setPayments
  };
};

export default usePayment;

