import React, { useState } from 'react';
import { Link } from 'react-router-dom';

// Core imports
import { ROUTES } from '../Config/Routes';
import { APP_CONFIG, COMPANY_INFO, LOCATIONS } from '../Utils/constants';

// Components
import Button from '../Components/Common/Button';
import Input from '../Components/Common/Input';
import Card from '../Components/Common/Card';
import LoadingSpinner from '../Components/Common/LoadingSpinner';

// Services
import { sendContactFormEmail } from '../Services/EmailService';

// Hooks
import { useApp } from '../Context/AppContext';

// Styles
import '../Styles/Contact.css';
import '../Styles/Variables.css';
import '../Styles/Global.css';
import '../Styles/Buttons.css';
import '../Styles/Forms.css';
import '../Styles/Cards.css';
import '../Styles/Responsive.css';
import '../Styles/Animations.css';

const Contact = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    subject: '',
    message: '',
    preferredContact: 'email',
    newsletter: false
  });

  const [errors, setErrors] = useState({});
  const [touched, setTouched] = useState({});
  const [loading, setLoading] = useState(false);
  const [submitStatus, setSubmitStatus] = useState(null);
  const [activeLocation, setActiveLocation] = useState(0);

  const { addNotification } = useApp();

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));

    // Clear error for this field
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: '' }));
    }
  };

  const handleBlur = (e) => {
    const { name } = e.target;
    setTouched(prev => ({ ...prev, [name]: true }));
    validateField(name, formData[name]);
  };

  const validateField = (name, value) => {
    let error = '';

    switch (name) {
      case 'name':
        if (!value || value.trim().length < 2) {
          error = 'Name must be at least 2 characters';
        } else if (value.trim().length > 50) {
          error = 'Name cannot exceed 50 characters';
        } else if (!/^[a-zA-Z\s\-']+$/.test(value)) {
          error = 'Name can only contain letters, spaces, hyphens, and apostrophes';
        }
        break;

      case 'email':
        if (!value) {
          error = 'Email is required';
        } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) {
          error = 'Please enter a valid email address';
        }
        break;

      case 'phone':
        if (value && !/^\+?[1-9]\d{1,14}$/.test(value.replace(/[\s\-\(\)]/g, ''))) {
          error = 'Please enter a valid phone number';
        }
        break;

      case 'subject':
        if (!value) {
          error = 'Subject is required';
        } else if (value.length < 3) {
          error = 'Subject must be at least 3 characters';
        } else if (value.length > 100) {
          error = 'Subject cannot exceed 100 characters';
        }
        break;

      case 'message':
        if (!value) {
          error = 'Message is required';
        } else if (value.length < 10) {
          error = 'Message must be at least 10 characters';
        } else if (value.length > 1000) {
          error = 'Message cannot exceed 1000 characters';
        }
        break;
    }

    setErrors(prev => ({ ...prev, [name]: error }));
    return !error;
  };

  const validateForm = () => {
    const fields = ['name', 'email', 'subject', 'message'];
    const newErrors = {};
    let isValid = true;

    fields.forEach(field => {
      const value = formData[field];
      if (!value || value.trim() === '') {
        newErrors[field] = 'This field is required';
        isValid = false;
      } else {
        const fieldValid = validateField(field, value);
        if (!fieldValid) isValid = false;
      }
    });

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!validateForm()) {
      // Scroll to first error
      const firstError = Object.keys(errors)[0];
      const element = document.querySelector(`[name="${firstError}"]`);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
      return;
    }

    setLoading(true);
    setSubmitStatus(null);

    try {
      await sendContactFormEmail(formData);
      setSubmitStatus('success');
      addNotification('Message sent successfully! We\'ll respond within 24 hours.', 'success');

      // Reset form
      setFormData({
        name: '',
        email: '',
        phone: '',
        subject: '',
        message: '',
        preferredContact: 'email',
        newsletter: false
      });
      setTouched({});
    } catch (error) {
      setSubmitStatus('error');
      addNotification(error.message || 'Failed to send message. Please try again.', 'error');
    } finally {
      setLoading(false);

      // Clear status after 5 seconds
      setTimeout(() => setSubmitStatus(null), 5000);
    }
  };

  const contactMethods = [
    {
      icon: '📞',
      title: 'Phone',
      details: COMPANY_INFO.phone,
      action: `tel:${COMPANY_INFO.phone.replace(/\s/g, '')}`,
      description: 'Mon-Fri 9am-8pm, Sat 10am-6pm'
    },
    {
      icon: '✉️',
      title: 'Email',
      details: COMPANY_INFO.email,
      action: `mailto:${COMPANY_INFO.email}`,
      description: '24/7 support, responses within 24h'
    },
    {
      icon: '💬',
      title: 'Live Chat',
      details: 'Chat with us',
      action: '#',
      description: 'Available during business hours'
    },
    {
      icon: '📍',
      title: 'Visit Us',
      details: COMPANY_INFO.city,
      action: '#locations',
      description: 'Three locations nationwide'
    }
