                    'rgba(212, 175, 55, 0.8)',
                    'rgba(0, 255, 136, 0.8)',
                    'rgba(51, 181, 229, 0.8)',
                    'rgba(255, 187, 51, 0.8)'
                  ]
                }]
              }}
              height={400}
            />
          </Card>
        </div>
      )}
    </div>
  );
};

export default Reports;

