  }

  try {
    await axios.post(`${API_BASE_URL}/2fa/disable`, {
      token
    }, {
      headers: { Authorization: `Bearer ${authToken}` }
    });

    return true;
  } catch (error) {
    console.error('2FA disable failed:', error);
    throw new Error(error.response?.data?.message || '2FA disable failed');
  }
};

