/**
 * LOCATION SERVICE - GOD MODE
 * Real location services with Google Maps API integration
 * Supports: Geocoding, distance calculation, real-time tracking
 */

import axios from 'axios';

// Google Maps API configuration
const GOOGLE_MAPS_API_KEY = process.env.REACT_APP_GOOGLE_MAPS_API_KEY;
const API_BASE_URL = process.env.REACT_APP_API_URL || 'https://api.carease.com/v1';

// Load Google Maps script
let mapsScriptLoaded = false;
let mapsScriptPromise = null;

/**
 * Load Google Maps API script
 * @returns {Promise} - Promise that resolves when script is loaded
 */
export const loadGoogleMapsScript = () => {
  if (mapsScriptLoaded) {
    return Promise.resolve();
  }

  if (mapsScriptPromise) {
    return mapsScriptPromise;
  }

  mapsScriptPromise = new Promise((resolve, reject) => {
    if (typeof window.google === 'object' && typeof window.google.maps === 'object') {
      mapsScriptLoaded = true;
      resolve();
      return;
    }

    const script = document.createElement('script');
    script.src = `https://maps.googleapis.com/maps/api/js?key=${GOOGLE_MAPS_API_KEY}&libraries=places,geometry`;
    script.async = true;
    script.defer = true;

    script.onload = () => {
      mapsScriptLoaded = true;
      resolve();
    };

    script.onerror = (error) => {
      mapsScriptPromise = null;
      reject(new Error('Failed to load Google Maps script'));
    };

    document.head.appendChild(script);
  });

  return mapsScriptPromise;
};

/**
 * Get current user location
 * @returns {Promise<Object>} - Current location {lat, lng}
 */
export const getCurrentLocation = () => {
  return new Promise((resolve, reject) => {
    if (!navigator.geolocation) {
      reject(new Error('Geolocation not supported by browser'));
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        resolve({
          lat: position.coords.latitude,
          lng: position.coords.longitude,
          accuracy: position.coords.accuracy,
          timestamp: position.timestamp
        });
      },
      (error) => {
        let errorMessage = 'Failed to get location';
        switch (error.code) {
          case error.PERMISSION_DENIED:
            errorMessage = 'Location permission denied';
            break;
          case error.POSITION_UNAVAILABLE:
            errorMessage = 'Location information unavailable';
            break;
          case error.TIMEOUT:
            errorMessage = 'Location request timeout';
            break;
        }
        reject(new Error(errorMessage));
      },
      {
        enableHighAccuracy: true,
        timeout: 10000,
        maximumAge: 0
      }
    );
  });
};

/**
 * Geocode address to coordinates
 * @param {string} address - Address to geocode
 * @returns {Promise<Object>} - Geocoding result
 */
export const geocodeAddress = async (address) => {
  try {
    await loadGoogleMapsScript();

    const geocoder = new window.google.maps.Geocoder();

    return new Promise((resolve, reject) => {
      geocoder.geocode({ address }, (results, status) => {
        if (status === 'OK' && results[0]) {
          const location = results[0].geometry.location;
          resolve({
            lat: location.lat(),
            lng: location.lng(),
            formattedAddress: results[0].formatted_address,
            placeId: results[0].place_id,
            components: results[0].address_components
          });
        } else {
          reject(new Error(`Geocoding failed: ${status}`));
        }
      });
    });
  } catch (error) {
    console.error('Geocoding error:', error);

    // Fallback to backend geocoding
    try {
      const response = await axios.post(`${API_BASE_URL}/location/geocode`, { address });
      return response.data;
    } catch (fallbackError) {
      throw new Error('Failed to geocode address');
    }
  }
};

